// --------------------
// ENCUESTAS (POR PROYECTO)
// --------------------
export async function obtenerEncuestasDB(projectId: string) {
  const userId = await requireUserId();
  if (!projectId) return [];

  UUIDSchema.parse(projectId);
  const scope = await getAccessScope();
  await assertProjectAccess(projectId, userId, scope);

  const scopedRole = scope.role === "director" || scope.role === "equipo";
  const schoolPattern = sqlLikeNormalizedPattern(scope.colegio);
  const poloPattern = sqlLikeNormalizedPattern(scope.polo);
  const cacheKey = scopeCacheKey("surveys:preview:v4", userId, scope, [projectId]);
  const cached = getServerCache<any[]>(cacheKey);
  if (cached) return cached;

  const baseSelect = sql;
  let rows: any[];

  // PERFORMANCE / TRANSFERENCIA:
  // Cuando el usuario tiene colegio/polo asignado, filtramos en SQL para no traer
  // comentarios de todo el proyecto y descartarlos recién en JavaScript.
  if (scopedRole && schoolPattern && poloPattern) {
    rows = await baseSelect`
      SELECT id, colegio, curso, polo, sexo, nombre, apellido, score, left(coalesce(positive, ''), ${COMMENT_PREVIEW_LIMIT}) AS positive, left(coalesce(improvement, ''), ${COMMENT_PREVIEW_LIMIT}) AS improvement, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ${projectId}::uuid
        AND (
          lower(translate(coalesce(colegio, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) LIKE ${schoolPattern}
          OR ${normalize(scope.colegio || "")} LIKE '%' || lower(translate(coalesce(colegio, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) || '%'
        )
        AND (
          lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) LIKE ${poloPattern}
          OR ${normalize(scope.polo || "")} LIKE '%' || lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) || '%'
        )
      ORDER BY id DESC
    `;
  } else if (scopedRole && schoolPattern) {
    rows = await baseSelect`
      SELECT id, colegio, curso, polo, sexo, nombre, apellido, score, left(coalesce(positive, ''), ${COMMENT_PREVIEW_LIMIT}) AS positive, left(coalesce(improvement, ''), ${COMMENT_PREVIEW_LIMIT}) AS improvement, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ${projectId}::uuid
        AND (
          lower(translate(coalesce(colegio, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) LIKE ${schoolPattern}
          OR ${normalize(scope.colegio || "")} LIKE '%' || lower(translate(coalesce(colegio, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) || '%'
        )
      ORDER BY id DESC
    `;
  } else if (scopedRole && poloPattern) {
    rows = await baseSelect`
      SELECT id, colegio, curso, polo, sexo, nombre, apellido, score, left(coalesce(positive, ''), ${COMMENT_PREVIEW_LIMIT}) AS positive, left(coalesce(improvement, ''), ${COMMENT_PREVIEW_LIMIT}) AS improvement, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ${projectId}::uuid
        AND (
          lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) LIKE ${poloPattern}
          OR ${normalize(scope.polo || "")} LIKE '%' || lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) || '%'
        )
      ORDER BY id DESC
    `;
  } else {
    rows = await baseSelect`
      SELECT id, colegio, curso, polo, sexo, nombre, apellido, score, left(coalesce(positive, ''), ${COMMENT_PREVIEW_LIMIT}) AS positive, left(coalesce(improvement, ''), ${COMMENT_PREVIEW_LIMIT}) AS improvement, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ${projectId}::uuid
      ORDER BY id DESC
    `;
  }

  // Filtro de seguridad final en JS por si algún nombre vino con variantes raras.
  const result = !scopedRole
    ? rows
    : (rows as any[]).filter((r) => matchesScopedText(r?.colegio, scope.colegio) && matchesScopedText(r?.polo, scope.polo));

  setServerCache(cacheKey, result, scopedRole ? 120_000 : 60_000);
  return result;
}


export async function obtenerComentarioCompletoEncuestaDB(projectId: string, encuestaId: string) {
  const userId = await requireUserId();
  if (!projectId || !encuestaId) return null;

  UUIDSchema.parse(projectId);
  const scope = await getAccessScope();
  await assertProjectAccess(projectId, userId, scope);

  const cacheKey = scopeCacheKey("survey-comment-full:v1", userId, scope, [projectId, String(encuestaId)]);
  const cached = getServerCache<{ id: string; positive: string; improvement: string } | null>(cacheKey);
  if (cached) return cached;

  const rows = await sql`
    SELECT
      id,
      colegio,
      polo,
      positive,
      improvement
    FROM encuestas
    WHERE project_id = ${projectId}::uuid
      AND id::text = ${String(encuestaId)}
    LIMIT 1
  `;

  const row = (rows as any[])?.[0];
  if (!row) return null;

  const scopedRole = scope.role === "director" || scope.role === "equipo";
  if (scopedRole) {
    const bySchool = matchesScopedText(row?.colegio, scope.colegio);
    const byPolo = matchesScopedText(row?.polo, scope.polo);
    if (!bySchool || !byPolo) return null;
  }

  const result = {
    id: String(row.id),
    positive: String(row.positive || ""),
    improvement: String(row.improvement || ""),
  };

  setServerCache(cacheKey, result, 300_000);
  return result;
}

// Para comparativas NPS de red/polo en Director: mantiene scope de polo,
// pero no restringe por colegio para poder ver el ranking del polo completo.
export async function obtenerEncuestasComparativoPoloDB(projectId: string) {
  const userId = await requireUserId();
  if (!projectId) return [];

  UUIDSchema.parse(projectId);
  const scope = await getAccessScope();
  await assertProjectAccess(projectId, userId, scope);

  const shouldFilterByPolo = scope.role === "director" || scope.role === "equipo";
  const poloPattern = shouldFilterByPolo ? sqlLikeNormalizedPattern(scope.polo) : "";
  const cacheKey = scopeCacheKey("surveys:polo:v2", userId, scope, [projectId]);
  const cached = getServerCache<any[]>(cacheKey);
  if (cached) return cached;

  let rows: any[];
  if (shouldFilterByPolo && poloPattern) {
    rows = await sql`
      SELECT id, colegio, polo, score, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ${projectId}::uuid
        AND (
          lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) LIKE ${poloPattern}
          OR ${normalize(scope.polo || "")} LIKE '%' || lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) || '%'
        )
      ORDER BY id DESC
    `;
  } else {
    rows = await sql`
      SELECT id, colegio, polo, score, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ${projectId}::uuid
      ORDER BY id DESC
    `;
  }

  const result = shouldFilterByPolo && scope.polo
    ? (rows as any[]).filter((r) => matchesScopedText(r?.polo, scope.polo))
    : rows;

  setServerCache(cacheKey, result, 180_000);
  return result;
}


export async function obtenerEncuestasComparativoPoloBatchDB(projectIdsUnsafe: string[]) {
  const userId = await requireUserId();
  const rawIds = Array.isArray(projectIdsUnsafe) ? projectIdsUnsafe : [];
  const uniqueIds = Array.from(new Set(rawIds.map((id) => String(id || "").trim()).filter(Boolean)))
    .filter((id) => UUIDSchema.safeParse(id).success)
    .slice(0, 40);

  if (uniqueIds.length === 0) return [];

  const scope = await getAccessScope();

  let allowedIds = uniqueIds;
  if (scope.role === "admin" && scope.hasProjectScope) {
    const allowedSet = new Set([...scope.projectIds, ...scope.compareProjectIds].map(String));
    allowedIds = uniqueIds.filter((id) => allowedSet.has(id));
  } else if (scope.role !== "admin") {
    const allowedSet = new Set([...scope.projectIds, ...scope.compareProjectIds].map(String));
    allowedIds = uniqueIds.filter((id) => allowedSet.has(id));
  }

  if (allowedIds.length === 0) return [];

  const shouldFilterByPolo = scope.role === "director" || scope.role === "equipo";
  const poloPattern = shouldFilterByPolo ? sqlLikeNormalizedPattern(scope.polo) : "";
  const cacheKey = scopeCacheKey("surveys:polo-batch:v1", userId, scope, [allowedIds.sort().join(",")]);
  const cached = getServerCache<any[]>(cacheKey);
  if (cached) return cached;

  let rows: any[];
  if (shouldFilterByPolo && poloPattern) {
    rows = await sql`
      SELECT project_id::text AS project_id, id, colegio, polo, score, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ANY(${allowedIds}::uuid[])
        AND (
          lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) LIKE ${poloPattern}
          OR ${normalize(scope.polo || "")} LIKE '%' || lower(translate(coalesce(polo, ''), 'ÁÉÍÓÚÜÑáéíóúüñ', 'AEIOUUNaeiouun')) || '%'
        )
      ORDER BY project_id, id DESC
    `;
  } else {
    rows = await sql`
      SELECT project_id::text AS project_id, id, colegio, polo, score, NULL::text AS created_at, NULL::text AS date
      FROM encuestas
      WHERE project_id = ANY(${allowedIds}::uuid[])
      ORDER BY project_id, id DESC
    `;
  }

  const result = shouldFilterByPolo && scope.polo
    ? (rows as any[]).filter((r) => matchesScopedText(r?.polo, scope.polo))
    : rows;

  setServerCache(cacheKey, result, 180_000);
  return result;
}

