export async function compararProyectosDB(projectIdA: string, projectIdB: string) {
  const userId = await requireUserId();
  const scope = await getAccessScope();
  const scopedRole = scope.role === "director" || scope.role === "equipo";

  UUIDSchema.parse(projectIdA);
  UUIDSchema.parse(projectIdB);

  await assertProjectAccess(projectIdA, userId, scope);
  await assertProjectAccess(projectIdB, userId, scope);

  const [rowsA, rowsB, projA, projB] = await Promise.all([
    sql`SELECT colegio, polo, score, tags FROM encuestas WHERE project_id = ${projectIdA}::uuid LIMIT 5000`,
    sql`SELECT colegio, polo, score, tags FROM encuestas WHERE project_id = ${projectIdB}::uuid LIMIT 5000`,
    sql`SELECT nombre FROM projects WHERE id = ${projectIdA}::uuid LIMIT 1`,
    sql`SELECT nombre FROM projects WHERE id = ${projectIdB}::uuid LIMIT 1`,
  ]);

  const filteredRowsProjectA = !scopedRole
    ? (rowsA as any[])
    : (rowsA as any[]).filter((r) => matchesScopedText(r?.colegio, scope.colegio) && matchesScopedText(r?.polo, scope.polo));
  const filteredRowsProjectB = !scopedRole
    ? (rowsB as any[])
    : (rowsB as any[]).filter((r) => matchesScopedText(r?.colegio, scope.colegio) && matchesScopedText(r?.polo, scope.polo));

  function calcStats(rows: any[], projectId: string, nombre: string) {
    const total = rows.length;
    const scores = rows.map((r) => Number(r.score) || 0).filter((s) => s > 0);
    const avg = scores.length ? scores.reduce((a, b) => a + b, 0) / scores.length : 0;

    const promoters  = rows.filter((r) => (Number(r.score) || 0) >= 9).length;
    const passives   = rows.filter((r) => { const s = Number(r.score) || 0; return s >= 7 && s <= 8; }).length;
    const detractors = rows.filter((r) => { const s = Number(r.score) || 0; return s > 0 && s < 7; }).length;
    const nps = total ? Math.round(((promoters - detractors) / total) * 100) : 0;

    const tagCount = new Map<string, number>();
    for (const r of rows) {
      const raw = r.tags;
      const tags: string[] = Array.isArray(raw)
        ? raw
        : typeof raw === "string"
        ? raw.replace(/[{}]/g, "").split(",").map((t: string) => t.trim()).filter(Boolean)
        : [];
      for (const t of tags) tagCount.set(t, (tagCount.get(t) ?? 0) + 1);
    }
    const topTags = Array.from(tagCount.entries())
      .sort((a, b) => b[1] - a[1])
      .slice(0, 8)
      .map(([tag, count]) => ({ tag, count }));

    const schoolMap = new Map<string, { scores: number[]; total: number }>();
    for (const r of rows) {
      const col = String(r.colegio || "Sin colegio");
      const s = Number(r.score) || 0;
      if (!schoolMap.has(col)) schoolMap.set(col, { scores: [], total: 0 });
      const entry = schoolMap.get(col)!;
      entry.total++;
      if (s > 0) entry.scores.push(s);
    }
    const bySchool = Array.from(schoolMap.entries())
      .map(([colegio, data]) => {
        const sc = data.scores;
        const schoolAvg = sc.length ? sc.reduce((a, b) => a + b, 0) / sc.length : 0;
        const sp = sc.filter((s) => s >= 9).length;
        const sd = sc.filter((s) => s > 0 && s < 7).length;
        const snps = sc.length ? Math.round(((sp - sd) / sc.length) * 100) : 0;
        return { colegio, avg: parseFloat(schoolAvg.toFixed(2)), total: data.total, nps: snps };
      })
      .sort((a, b) => b.avg - a.avg);

    return { projectId, nombre, total, avg: parseFloat(avg.toFixed(2)), nps, promoters, passives, detractors, participationRate: 0, topTags, bySchool };
  }

  return {
    a: calcStats(filteredRowsProjectA as any[], projectIdA, (projA as any[])[0]?.nombre ?? "Proyecto A"),
    b: calcStats(filteredRowsProjectB as any[], projectIdB, (projB as any[])[0]?.nombre ?? "Proyecto B"),
  };
}

